import{c as s,Q as a,j as n,m as t}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Session keys","description":"The short-lived signers that handle your day-to-day actions.","frontmatter":{"title":"Session keys","description":"The short-lived signers that handle your day-to-day actions."},"headers":[],"relativePath":"policy/session-keys.md","filePath":"policy/session-keys.md","lastUpdated":1780245214000}'),o={name:"policy/session-keys.md"};function i(r,e,l,d,c,p){return a(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="session-keys" tabindex="-1">Session keys <a class="header-anchor" href="#session-keys" aria-label="Permalink to &quot;Session keys&quot;">​</a></h1><p>A <strong>session key</strong> is a short-lived ECDSA key with <strong>narrow scope</strong> installed in your MuHaven wallet (a ZeroDev-powered smart account) by your passkey. For its lifetime (default 1 hour), it can sign MuHaven UserOps without prompting you for a passkey on every action.</p><p>Session keys are how Confirm-per-action tier feels frictionless without sacrificing scope safety. They&#39;re also what powers the live <strong>Scoped autonomy</strong> tier: a bounded session key held by the broker daemon signs the agent&#39;s buys, sells, and claims within a per-trade cap + TTL, without prompting you. (The Policy-bound cron is also designed to sign via a session key, but that engine is built and disabled in every deployment today — see <a href="/policy/tiered-autonomy">Tiered autonomy</a>.)</p><h2 id="what-the-session-key-can-do" tabindex="-1">What the session key can do <a class="header-anchor" href="#what-the-session-key-can-do" aria-label="Permalink to &quot;What the session key can do&quot;">​</a></h2><p>Locked at install time by the <code>@zerodev/permissions</code> <code>CallPolicy</code> / <code>GasPolicy</code> / <code>RateLimitPolicy</code> validators:</p><ul><li><strong>Target contracts:</strong> an allowlist of MuHaven contract addresses (Subscription, RedemptionQueue, YieldSnapshot, RiskParams, etc.).</li><li><strong>Function selectors:</strong> an allowlist of specific 4-byte selectors. A transfer to an arbitrary EOA is not in the list.</li><li><strong>Value cap per call:</strong> session key cannot send more than $N in one UserOp.</li><li><strong>Value cap per epoch:</strong> session key cannot send more than $N total in the validity window (your daily-spend ceiling, if set).</li><li><strong><code>validUntil</code>:</strong> a Unix timestamp after which the validator refuses to authorize anything. Default 1 hour from install.</li></ul><p>You can inspect the current session-key state via <code>muhaven.policy.session_key_status</code> (MCP) or by asking HavenBot: <em>&quot;Show my session-key permissions.&quot;</em></p><h2 id="why-a-session-key-instead-of-just-use-the-passkey" tabindex="-1">Why a session key instead of &quot;just use the passkey&quot; <a class="header-anchor" href="#why-a-session-key-instead-of-just-use-the-passkey" aria-label="Permalink to &quot;Why a session key instead of &quot;just use the passkey&quot;&quot;">​</a></h2><p>Three reasons:</p><ol><li><strong>UX.</strong> Touch ID / Windows Hello on every click is exhausting. The session key signs without prompting; the passkey ceremony requires a biometric prompt every time.</li><li><strong>Scope reduction.</strong> Your passkey signs <em>anything</em> the MuHaven wallet asks. The session key signs only what the validators allow. A leaked session key isn&#39;t a drain-the-account key.</li><li><strong>Daemon-friendly.</strong> A passkey requires a user-present WebAuthn ceremony. A session key can be invoked without user interaction — this is what lets the broker daemon sign for the live <strong>Scoped autonomy</strong> tier (and, by the same mechanism, the designed-but-disabled Policy-bound cron).</li></ol><h2 id="lifecycle" tabindex="-1">Lifecycle <a class="header-anchor" href="#lifecycle" aria-label="Permalink to &quot;Lifecycle&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>You sign in / change tier</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ ZeroDev kernel install_session_key(                          │</span></span>
<span class="line"><span>│   target_allowlist: [...MuHaven contracts...],               │</span></span>
<span class="line"><span>│   selector_allowlist: [...MuHaven SDK fns...],               │</span></span>
<span class="line"><span>│   value_cap: 5_000_000_000,    // $5K per call               │</span></span>
<span class="line"><span>│   epoch_cap: 50_000_000_000,   // $50K per epoch             │</span></span>
<span class="line"><span>│   validUntil: now + 1h,                                      │</span></span>
<span class="line"><span>│ )                                                             │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       │ install signed by passkey</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>┌──────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ Session key (private half held by broker / browser)          │</span></span>
<span class="line"><span>│ signs UserOps within scope for 1 hour                        │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       │ on /pause: validator uninstalled</span></span>
<span class="line"><span>       │ on validUntil: validator refuses to authorize</span></span>
<span class="line"><span>       ▼</span></span>
<span class="line"><span>   Refuses; next action prompts passkey for fresh install</span></span></code></pre></div><h2 id="where-the-session-key-private-half-lives" tabindex="-1">Where the session-key private half lives <a class="header-anchor" href="#where-the-session-key-private-half-lives" aria-label="Permalink to &quot;Where the session-key private half lives&quot;">​</a></h2><p>Depends on the surface:</p><table tabindex="0"><thead><tr><th>Surface</th><th>Private half held by</th></tr></thead><tbody><tr><td><strong>HavenBot dashboard</strong></td><td>Browser-local (<code>window.localStorage</code> + Web Crypto subtle key, encrypted with a wallet-derived key)</td></tr><tr><td><strong><code>@muhaven/mcp</code></strong></td><td><code>muhaven-broker</code> daemon — in OS keychain or 0600-mode file. This daemon is what signs for the live <strong>Scoped autonomy</strong> tier.</td></tr><tr><td><strong>OpenClaw + Telegram inline</strong></td><td>Backend service-secret bound to the inline tier; signed server-side via the MuHaven wallet&#39;s session-key validator</td></tr><tr><td><strong>OpenClaw + Telegram Mini-App OTP</strong></td><td>Same as inline — backend-side, gated by Mini App OTP</td></tr><tr><td><strong>OpenClaw + Telegram passkey deeplink</strong></td><td>Browser-local (deeplink to dashboard <code>/agent/confirm</code>)</td></tr><tr><td><strong>Hosted Checkout</strong></td><td>Browser-local during checkout; transient session, no persistence</td></tr><tr><td><strong>Policy-bound cron</strong> <em>(designed; cron disabled in every deployment today)</em></td><td>Backend cron service, stored in TPM-backed or KMS-bound keystore on the policy-engine host</td></tr></tbody></table><p>The session key <strong>never</strong> lives in an LLM process, an env var, or a long-lived browser cookie. The broker pattern + OS keychain ensures the LLM-jailbreak path cannot exfiltrate the key.</p><h2 id="why-the-broker-daemon-for-mcp" tabindex="-1">Why the broker daemon for MCP <a class="header-anchor" href="#why-the-broker-daemon-for-mcp" aria-label="Permalink to &quot;Why the broker daemon for MCP&quot;">​</a></h2><p><code>@muhaven/mcp</code> is the most security-sensitive surface because it runs alongside an LLM you brought yourself. If the session key lived in the MCP server process (e.g., loaded from env block), a jailbroken LLM could read it. The broker daemon:</p><ul><li>Runs in a <strong>separate process</strong> under your user.</li><li>Holds the key in OS keychain (or 0600-mode file).</li><li>Exposes only <code>sign_hash</code> over Unix socket / named pipe (no network surface).</li><li>POSIX peer-credentials check ACLs the broker to only the owning user&#39;s processes.</li></ul><p>See <a href="/mcp/broker">Broker daemon</a> for the full architecture.</p><h2 id="rate-limit-policy-validator" tabindex="-1">Rate-limit policy validator <a class="header-anchor" href="#rate-limit-policy-validator" aria-label="Permalink to &quot;Rate-limit policy validator&quot;">​</a></h2><p>The session key carries a <code>RateLimitPolicy</code> validator that throttles call rate even within the value-cap window. Default rate limits:</p><ul><li>60 calls per minute (read tools — even read tools sometimes write to encrypted accumulators).</li><li>10 propose calls per minute.</li><li>3 commits per minute (settled UserOps).</li></ul><p>A jailbroken LLM that tried to drain your MuHaven wallet via thousands of small buys would hit the rate-limit before the value-cap kicks in.</p><h2 id="when-session-keys-are-uninstalled" tabindex="-1">When session keys are uninstalled <a class="header-anchor" href="#when-session-keys-are-uninstalled" aria-label="Permalink to &quot;When session keys are uninstalled&quot;">​</a></h2><p>Three triggers:</p><ol><li><strong><code>/pause</code></strong> — <code>uninstallPlugin(sessionKeyValidator)</code> removes the validator immediately. ≤1 Arb block.</li><li><strong><code>validUntil</code> expiry</strong> — the validator silently stops accepting signatures past the timestamp. No on-chain action; the MuHaven wallet&#39;s <code>validateUserOp</code> returns invalid.</li><li><strong>Manual uninstall</strong> — <code>muhaven.policy.session_key_status</code> shows the current install; ask HavenBot <em>&quot;Uninstall my session key&quot;</em> to force a reinstall on next action.</li></ol><h2 id="why-not-longer-ttls" tabindex="-1">Why not longer TTLs? <a class="header-anchor" href="#why-not-longer-ttls" aria-label="Permalink to &quot;Why not longer TTLs?&quot;">​</a></h2><p>We considered 24h / 7d / &quot;until you sign out&quot;. The 1h default balances:</p><ul><li><strong>UX friction</strong> — a working session is rarely longer than 1h without a natural break for re-auth.</li><li><strong>Phishing window</strong> — if your laptop is briefly unattended, 1h is the maximum exposure window.</li><li><strong>Reg BI proxy</strong> — short TTLs satisfy &quot;investor must be present for high-stakes decisions&quot; framing.</li></ul><p>You can configure a different TTL via <code>VITE_SESSION_KEY_DURATION_SEC</code> (frontend) / <code>MUHAVEN_SESSION_KEY_TTL_SEC</code> (MCP broker).</p><h2 id="what-you-can-t-do-with-a-session-key" tabindex="-1">What you can&#39;t do with a session key <a class="header-anchor" href="#what-you-can-t-do-with-a-session-key" aria-label="Permalink to &quot;What you can&#39;t do with a session key&quot;">​</a></h2><ul><li><strong>Send funds to a non-MuHaven address.</strong> Not in the target allowlist.</li><li><strong>Upgrade your MuHaven wallet&#39;s validator config.</strong> Reserved for passkey signature.</li><li><strong>Sign cross-chain UserOps.</strong> Session key is chain-bound; cross-chain ops require passkey re-authorization.</li><li><strong>Drain your MuHaven wallet.</strong> Value-cap + rate-limit + selector-allowlist make this structurally impossible.</li></ul><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/policy/tiered-autonomy">Tiered autonomy</a> — how session keys map to tiers.</li><li><a href="/policy/pause">The /pause kill-switch</a> — kill-switch in depth.</li><li><a href="/policy/audit-log">Audit log</a> — what session-key activity gets recorded.</li></ul>`,35)])])}const y=s(o,[["render",i]]);export{u as __pageData,y as default};
